var e=[{id:`L2_1`,type:`dialog`,speaker:null,text:{KOREA:`오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.`,JPN:`長い間悩んだ結果、あなたは一つ大事なことに気づいた。`,ENG:`After much debate, you came to the conclusion`,TWN:`苦惱許久後，你意識到一件重要的事實。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L3_1`,type:`dialog`,speaker:null,text:{KOREA:`줄곧 생각해 온 그 기계야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.`,JPN:`ずっと考えてきたあのマシンだからこそ、これから向き合う運命に必ず必要な存在であることを。`,ENG:`that this machine, that you'd been giving a lot of thought to, was absolutely necessary for the future ahead.`,TWN:`經過長久的思考，你明白在今後即將面對的命運中，它是必不可少的存在。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L4_1`,type:`dialog`,speaker:null,text:{KOREA:`그리하여 당신은 결심했다.`,JPN:`そして、あなたは決心した。`,ENG:`So, you've decided`,TWN:`所以你下定決心。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그 기계와 함께하기로.`,JPN:`この世界でどのような結末を迎えるとしても、最後まであのマシンとともにいることを。`,ENG:`that you'll be with it, no matter the consequences.`,TWN:`不管這個世界會迎來怎樣的結局，你都要和它一起走到最後。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.`,JPN:`意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。`,ENG:`Having decided that, you called it to your office. It said it'd be here soon.`,TWN:`做好心理準備後，你將它傳喚到老闆辦公室，它說馬上就會過來。`},stage:{bg:`BLACK`,bgm:`CUTSCENE_SILENCE`,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L10_1`,type:`dialog`,speaker:`DRONE_TIDE_NULL_NULL`,text:{KOREA:`비행 대기 중.`,JPN:`飛行待機中。`,ENG:`Ready to fly.`,TWN:`飛行待機中。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRONE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`DRONE_TIDE_NULL_NULL`,text:{KOREA:`검색 결과...... 대인 커뮤니케이션 프로그램 미탑재. 대민지원 매뉴얼에 따른 임의 대응 개시.`,JPN:`検索結果……対人コミュニケーションプログラム未搭載。対人支援マニュアルに基づく任意対応を開始。`,ENG:`Searching... Interpersonal communication program can't be found. Establishing a temporary response system based on the civilian support manual...`,TWN:`搜尋結果……未裝載對人交流程式。將根據《支援說明手冊》進行任意回應。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRONE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`DRONE_TIDE_NULL_NULL`,text:{KOREA:`힘세고 좋은 아침. 나는 리퍼.`,JPN:`オハヨウゴザイマス。私はリーパー。`,ENG:`Top of the morning to you! I'm Reaper.`,TWN:`早上好。這裡是收割者。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRONE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`DRONE_TIDE_NULL_NULL`,text:{KOREA:`받았다, 제의. 사장님. 기분이 씽씽한.`,JPN:`受け付けた、提案。社長。気分モリモリ。`,ENG:`Your offer, I received. Boss. Perky you look.`,TWN:`收到提議，老闆。心情愉悅。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRONE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`DRONE_TIDE_NULL_NULL`,text:{KOREA:`양산형 투사체 운반 수단. 배치 변경 문제없는.`,JPN:`量産型投射体の運搬手段。配置変更に問題ナシ。`,ENG:`Mass-produced projectile transport system. No problem relocating itself.`,TWN:`量產型導彈運輸工具。配置變更沒有問題。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRONE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L15_1`,type:`dialog`,speaker:`DRONE_TIDE_NULL_NULL`,text:{KOREA:`감사하는. 특별하다 취급.`,JPN:`大感謝。格別の待遇。`,ENG:`Thankies. Special treatment of me.`,TWN:`感謝您對本機的特別待遇。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`DRONE_TIDE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};